const items = $input.all();

const find = (type) =>
  items.find(i => i.json.promptType === type)?.json?.content || "";

const videoSummary          = find("videoSummary");
const userGuide             = find("userGuide");
const productOverview       = find("productOverview");
const productDescription    = find("productDescription");
const researchReport        = find("researchReport");
const communicationStrategy = find("communicationStrategy");
const onePager              = find("onePager");
const elevatorPitch         = find("elevatorPitch");
const industryFeatureList   = find("industryFeatureList");
const marketingScript       = find("marketingScript");
const storyboard            = find("storyboard");
const screenplay            = find("screenplay");

return [{
  json: {
    productName: items[0]?.json?.productName || "Product",

    // Individual fields (for placeholders or selective use)
    videoSummary,
    userGuide,
    productOverview,
    productDescription,
    researchReport,
    communicationStrategy,
    onePager,
    elevatorPitch,
    industryFeatureList,
    marketingScript,
    storyboard,
    screenplay,

    // Full combined document (for single insert into Google Doc)
    fullDocument: `
VIDEO SUMMARY
${videoSummary}

USER GUIDE
${userGuide}

PRODUCT OVERVIEW
${productOverview}

PRODUCT DESCRIPTION
${productDescription}

RESEARCH REPORT
${researchReport}

COMMUNICATION STRATEGY
${communicationStrategy}

ONE PAGER
${onePager}

ELEVATOR PITCH
${elevatorPitch}

INDUSTRY FEATURE LIST
${industryFeatureList}

MARKETING SCRIPT
${marketingScript}

STORYBOARD
${storyboard}

SCREENPLAY
${screenplay}
    `.trim()
  }
}];
